pipeline.evaluate:
(() => {
  const items = [];
  document.querySelectorAll('.arxiv-result').forEach(result => {
    const titleEl = result.querySelector('.title');
    const linkEl = result.querySelector('.list-title a');
    const authorsEl = result.querySelector('.authors');
    if (titleEl && linkEl) {
      items.push({
        title: titleEl.textContent.trim(),
        url: 'https://arxiv.org' + linkEl.getAttribute('href'),
        authors: authorsEl ? authorsEl.textContent.trim() : ''
      });
    }
  });
  return items;
})()
